import type { UpstreamParameterMap } from '@arduconfig/param-metadata'

// Lazy loader for the imported ArduPilot upstream parameter metadata. Each
// vehicle's file is ~1.7 MB, so they're dynamic-imported (separate Vite
// chunks) only when that vehicle connects — they never weigh down the main
// bundle. Generated by scripts/import-ardupilot-params.mjs.
export async function loadUpstreamParameters(
  vehicle: string | undefined
): Promise<UpstreamParameterMap | undefined> {
  switch (vehicle) {
    case 'ArduCopter':
      return (await import('./arducopter.json')).default as UpstreamParameterMap
    case 'ArduPlane':
      return (await import('./arduplane.json')).default as UpstreamParameterMap
    case 'ArduRover':
      return (await import('./ardurover.json')).default as UpstreamParameterMap
    case 'ArduSub':
      return (await import('./ardusub.json')).default as UpstreamParameterMap
    default:
      return undefined
  }
}
